mapper.insert:
		/* oms-interfaces-order-sql-oracle insertPoCnfrmRequest */
		INSERT INTO TORDER_INTF_MAL_REQORDERCNFRM (
			  ICKEY
            , CNFRMREQORDERDAY
            , REQORDERDIV
            , SEQ
            , CNFRMREQORDERQTY
            , REQUESTDT
            , IFID
            , INSERTDATE
            , INSERTURKEY
            , UPDATEDATE
            , UPDATEURKEY
		) VALUES
		(
			   #{ickey}
			 , #{cnfrmreqorderday}
			 , #{reqorderdiv}
			 , #{seq}
			 , #{cnfrmreqorderqty}
			 , #{requestdt}
			 , #{ifid}
		     , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
		     , #{surkey}
		     , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
		     , #{surkey}
		)
